mapper.select:
SELECT A.PROP_CD, A.CMPX_CD, A.CMPX_TP, A.CMPX_NM,
       A.CMPX_ZIP_CD, A.CMPX_ADDR, A.CMPX_DTL_ADDR,
       A.CMPX_REPR_TEL, A.USE_YN
  FROM PMS.PMS_COMPLEX A
 WHERE A.PROP_CD = #{propCd}
   AND A.CMPX_CD = #{cmpxCd}

SELECT A.USER_ID, A.USER_NM, A.USER_TP, A.DEPT_CD,
       A.USER_MOBILE, A.USER_WK_STAT
  FROM PMS.PMS_USER_MTR A
 WHERE A.PROP_CD = #{propCd}
   AND A.CMPX_CD = #{cmpxCd}

   AND A.DEPT_CD = #{deptCd}

   AND A.USE_YN  = 'Y'
 ORDER BY A.USER_NM
